import os
import shutil
import getpass

def get_user_confirmation():
    """Asks the user for confirmation before proceeding with the directory purge."""
    while True:
        response = input("Are you sure you want to purge the directory? (y/n): ")
        if response.lower() == 'y':
            return True
        elif response.lower() == 'n':
            print("Purge cancelled.")
            return False
        else:
            print("Invalid input. Please enter 'y' or 'n'.")

def purge_directory(directory):
    """Recursively removes all files from the specified directory."""
    try:
        for root, dirs, files in os.walk(directory):
            for file in files:
                file_path = os.path.join(root, file)
                os.remove(file_path)
                print(f"Removed file: {file_path}")
    except Exception as e:
        print(f"Error purging directory: {e}")

def main():
    directory = '/home/user/challenge_dir'
    if not os.path.exists(directory):
        print(f"Directory '{directory}' does not exist.")
        return

    confirmation = get_user_confirmation()
    if not confirmation:
        return

    print(f"Purging directory '{directory}'...")
    purge_directory(directory)
    print(f"Purge complete.")

if __name__ == "__main__":
    main()
